package com.l3.logparser.config;

/**
 * Simple test class to verify advanced configuration functionality
 */
public class AdvancedConfigTest {

    public static void main(String[] args) {
        testAdvancedConfig();
        testApiPatternConfig();
        testConfigPersistence();
    }

    private static void testAdvancedConfig() {
        System.out.println("=== Testing AdvancedParserConfig ===");

        // Create new config
        AdvancedParserConfig config = new AdvancedParserConfig();

        // Test default patterns
        ApiPatternConfig apiConfig = config.getApiConfig();
        System.out.println("Default patterns loaded: " + apiConfig.getMessageStartPatterns().size());

        for (ApiPatternConfig.MessagePattern pattern : apiConfig.getMessageStartPatterns()) {
            System.out.println("Pattern: " + pattern.getName() + " (" + pattern.getType() + ") - " + 
                               (pattern.isEnabled() ? "ENABLED" : "DISABLED"));
        }

        // Test segment codes
        ApiPatternConfig.SegmentCodes codes = apiConfig.getSegmentCodes();
        System.out.println("BGM Passenger Code: " + codes.getBgmPassengerCode());
        System.out.println("LOC Departure Code: " + codes.getLocDepartureCode());
        System.out.println("DTM Departure Code: " + codes.getDtmDepartureCode());
        System.out.println("TDT Flight Position: " + codes.getTdtFlightPosition());
    }

    private static void testApiPatternConfig() {
        System.out.println("\n=== Testing ApiPatternConfig ===");

        ApiPatternConfig config = new ApiPatternConfig();
        config.loadDefaults();

        // Test adding a new pattern
        ApiPatternConfig.MessagePattern newPattern = 
            new ApiPatternConfig.MessagePattern("TEST_PATTERN", "contains", "TEST_VALUE", true);
        config.getMessageStartPatterns().add(newPattern);

        System.out.println("Added new pattern. Total patterns: " + config.getMessageStartPatterns().size());

        // Test modifying segment codes
        config.getSegmentCodes().setBgmPassengerCode("999");
        System.out.println("Modified BGM passenger code: " + config.getSegmentCodes().getBgmPassengerCode());
    }

    private static void testConfigPersistence() {
        System.out.println("\n=== Testing Configuration Persistence ===");

        try {
            // Create and modify config
            AdvancedParserConfig config = new AdvancedParserConfig();
            config.getApiConfig().getSegmentCodes().setBgmPassengerCode("777");

            // Save to file
            boolean saveSuccess = config.saveToFile();
            System.out.println("Save to file: " + (saveSuccess ? "SUCCESS" : "FAILED"));

            // Load new instance
            AdvancedParserConfig loadedConfig = new AdvancedParserConfig();
            String loadedCode = loadedConfig.getApiConfig().getSegmentCodes().getBgmPassengerCode();
            System.out.println("Loaded BGM passenger code: " + loadedCode);

            // Check if persistence worked
            System.out.println("Persistence test: " + ("777".equals(loadedCode) ? "SUCCESS" : "FAILED"));

        } catch (Exception e) {
            System.out.println("Persistence test FAILED: " + e.getMessage());
        }
    }
}
